void main() {
  bool showDiscount = true;
  double discountRate = 0.1;
  var basePrices = [100.0, 200.0, 300.0];

  var prices = [
    '--- Prices ---',
    for (var price in basePrices)
      if (showDiscount)
        price * (1 - discountRate)
      else
        price,
    '--- Total ---',
  ];

  print(prices);

  // Conditional set elements
  var isAdmin = true;
  var roles = <String>{
    'user',
    if (isAdmin) 'admin',
    if (isAdmin) 'moderator',
  };

  print(roles);
}
